 25→  mobileApi,
 26→  type CursorPage,
 27→  type JournalItem,
 28→} from '../../lib/api/mobileApi';
 29→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 30→
 31→type Props = CompositeScreenProps<
 32→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 33→  NativeStackScreenProps<RootStackParamList>
 34→>;
