139→    [feedQuery.data?.pages],
140→  );
141→
142→  const onRefresh = async () => {
143→    setRefreshing(true);
144→    try {
145→      await feedQuery.refetch();
146→    } finally {
147→      setRefreshing(false);
148→    }
149→  };
150→
151→  const handleQuickAction = (key: string) => {
152→    if (key === 'canvas') {
153→      navigation.navigate('Canvas');
154→    } else if (key === 'freedom_wall') {
155→      navigation.navigate('FreedomWall');
156→    } else if (key === 'universe') {
157→      navigation.navigate('Universe');
158→    } else {
159→      setActiveFilter(key);
160→    }
161→  };
162→
163→  return (
164→    <SafeAreaView
165→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
166→      edges={['top']}>
167→      {/* Branded header */}
168→      <View
169→        style={[
170→          styles.header,
171→          {borderBottomColor: colors.borderCard},
172→        ]}>
173→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
174→          iskrib
175→        </Text>
176→      </View>
177→
178→      {/* Filter chips */}
179→      <View style={styles.chipRow}>
180→        <ScrollView
181→          horizontal
182→          showsHorizontalScrollIndicator={false}
183→          contentContainerStyle={styles.chipScroll}>
184→          {QUICK_ACTIONS.map(action => (
185→            <Chip
