225→              <PostCardSkeleton />
226→            </View>
227→          ) : null
228→        }
229→        keyExtractor={item => item.id}
230→        renderItem={({item}) => {
231→          const preview = extractPlainText(item.content).slice(0, 180);
232→          const likeCount = resolveCount(
233→            item.like_count,
234→            item.likes_count,
235→          );
236→          const commentCount = resolveCount(
237→            item.comment_count,
238→            item.comments_count,
239→          );
240→          const bookmarkCount = resolveCount(item.bookmark_count);
241→          const bannerImage = extractBannerImage(
242→            item.content,
243→            (item as any).images,
244→          );
245→
246→          return (
247→            <PostCard
248→              title={item.title || 'Untitled Post'}
249→              bodyPreview={preview || 'No preview text available.'}
250→              authorName={item.users?.name || 'Unknown author'}
251→              authorAvatar={item.users?.image_url}
252→              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
253→              bannerImage={bannerImage}
254→              postType={item.post_type}
255→              likeCount={likeCount}
256→              commentCount={commentCount}
257→              bookmarkCount={bookmarkCount}
258→              onPress={() =>
259→                navigation.navigate('PostDetail', {journalId: item.id})
260→              }
261→            />
262→          );
263→        }}
264→        ItemSeparatorComponent={() => <View style={styles.separator} />}
265→      />
266→
267→      {/* FAB Write Button */}
268→      <Pressable
