import React from 'react';
import {Image, Pressable, StyleSheet, Text, View} from 'react-native';
import {useTheme} from '../../theme/ThemeProvider';
import {fonts, typeScale} from '../../theme/typography';
import {spacing, radii, shadows} from '../../theme/spacing';
import {Avatar} from '../Avatar';
import {ActionBar} from './ActionBar';

interface PostCardProps {
  title: string;
  bodyPreview: string;
  authorName: string;
  authorAvatar?: string | null;
  authorBadge?: 'legend' | 'og' | null;
  bannerImage?: string | null;
  postType?: string;
  readingTime?: string;
  likeCount: number;
  commentCount: number;
  bookmarkCount?: number;
  isLiked?: boolean;
  isBookmarked?: boolean;
  onPress?: () => void;
  onLike?: () => void;
  onComment?: () => void;
  onBookmark?: () => void;
  onRepost?: () => void;
}

export function PostCard({
  title,
  bodyPreview,
  authorName,
  authorAvatar,
  authorBadge,
  bannerImage,
  postType,
  readingTime,
  likeCount,
  commentCount,
  bookmarkCount,
  isLiked,
  isBookmarked,
  onPress,
  onLike,
  onComment,
  onBookmark,
  onRepost,
}: PostCardProps) {
  const {colors} = useTheme();
  const s = shadows(colors);

  return (
    <Pressable
      onPress={onPress}
      style={({pressed}) => [
        styles.card,
        {
          backgroundColor: colors.bgCard,
          borderColor: colors.borderCard,
        },
        s.card,
        pressed && styles.pressed,
      ]}>
      {bannerImage ? (
        <Image
          source={{uri: bannerImage}}
          style={styles.banner}
          resizeMode="cover"
        />
      ) : null}

      <View style={styles.content}>
        {/* Author row */}
        <View style={styles.authorRow}>
          <Avatar uri={authorAvatar} name={authorName} size={22} badge={authorBadge} />
          <Text
            style={[styles.authorName, {color: colors.textSecondary}]}
            numberOfLines={1}>
            {authorName}
          </Text>
          {postType && postType !== 'journal' ? (
            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
              <Text style={[styles.typeText, {color: colors.accentSage}]}>
                {postType}
              </Text>
            </View>
          ) : null}
          {readingTime ? (
            <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
              <Text style={[styles.typeText, {color: colors.accentSage}]}>
                {readingTime}
              </Text>
            </View>
          ) : null}
        </View>

        {/* Title */}
        <Text
          style={[styles.title, {color: colors.textHeading}]}
          numberOfLines={2}>
          {title}
        </Text>

        {/* Body preview */}
        {bodyPreview ? (
          <Text
            style={[styles.body, {color: colors.textBody}]}
            numberOfLines={3}>
            {bodyPreview}
          </Text>
        ) : null}
      </View>

      <ActionBar
        likeCount={likeCount}
        commentCount={commentCount}
        bookmarkCount={bookmarkCount}
        isLiked={isLiked}
        isBookmarked={isBookmarked}
        onLike={onLike}
        onComment={onComment}
        onBookmark={onBookmark}
        onRepost={onRepost}
      />
    </Pressable>
  );
}

const styles = StyleSheet.create({
  card: {
    borderRadius: radii.xl,
    borderWidth: 1,
    overflow: 'hidden',
  },
  pressed: {
    opacity: 0.95,
    transform: [{scale: 0.995}],
  },
  banner: {
    width: '100%',
    height: 180,
  },
  content: {
    paddingHorizontal: spacing.lg,
    paddingTop: spacing.md,
    paddingBottom: spacing.sm,
    gap: spacing.sm,
  },
  authorRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.sm,
  },
  authorName: {
    fontSize: 13,
    fontFamily: fonts.ui.medium,
    flex: 1,
  },
  typePill: {
    borderRadius: radii.lg,
    paddingHorizontal: spacing.sm,
    paddingVertical: 2,
  },
  typeText: {
    fontSize: 11,
    fontFamily: fonts.ui.medium,
  },
  title: {
    ...typeScale.cardTitle,
  },
  body: {
    ...typeScale.bodySmall,
    lineHeight: 20,
  },
});

