import React from 'react';
import Svg, {Path, G, Circle, Line, Polyline, Rect} from 'react-native-svg';

export interface IconProps {
  size?: number;
  color?: string;
  filled?: boolean;
  strokeWidth?: number;
}

const defaults = {size: 24, color: '#888', strokeWidth: 1.8};

function I({
  size = defaults.size,
  color = defaults.color,
  children,
}: IconProps & {children: React.ReactNode}) {
  return (
    <Svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color}
      strokeWidth={defaults.strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round">
      {children}
    </Svg>
  );
